mapper.insert:
insert into visitor(
	visit_date, visitor_id
) values (
	TRUNC(CAST(SYSTIMESTAMP AT TIME ZONE 'Asia/Seoul' AS DATE)),
	#{visitorId}
)

mapper.update:
update visitor set is_login = 'Y'
where visit_date = TRUNC(CAST(SYSTIMESTAMP AT TIME ZONE 'Asia/Seoul' AS DATE))
	and visitor_id = #{visitorId}

merge into visit use v
using dual on (
	v.use_date = TRUNC(CAST(SYSTIMESTAMP AT TIME ZONE 'Asia/Seoul' AS DATE))
	and v.use_type = #{value}
)
when matched then
	update set v.use_count = v.use_count + 1
when not matched then
	insert(use_date, use_type, use_count)
	values(TRUNC(CAST(SYSTIMESTAMP AT TIME ZONE 'Asia/Seoul' AS DATE)),#{value},1)
